import"./hoisted.CnLosnT4.js";document.addEventListener("DOMContentLoaded",()=>{[{selector:".example",keyword:"Lời giải",colors:{text:"text-orange-600",border:"border-orange-200",hover:"hover:bg-orange-50"}},{selector:".practice",keyword:"Gợi ý",colors:{text:"text-green-600",border:"border-green-300",hover:"hover:bg-green-50"}},{selector:".exercise",keyword:"Đáp án",colors:{text:"text-pink-600",border:"border-pink-200",hover:"hover:bg-pink-50"}}].forEach(e=>{document.querySelectorAll(e.selector).forEach(d=>{const l=e.keyword+":",n=d.querySelector(".box-content")||d,s=Array.from(n.children).find(t=>{const r=t.textContent.trim();return r===l||r===e.keyword||r.startsWith(l)});if(s){const t=document.createElement("div");t.className=`solution-wrapper hidden mt-4 pt-4 border-t ${e.colors.border}`;let r=s.nextSibling;for(;r;){let i=r.nextSibling;t.appendChild(r),r=i}t.insertBefore(s,t.firstChild);const o=document.createElement("button");o.className=`mt-5 px-4 py-2 bg-white rounded-lg shadow-sm border transition-colors text-[0.95rem] font-bold flex items-center gap-2 ${e.colors.text} ${e.colors.border} ${e.colors.hover} w-fit`,o.innerHTML=`<span class="text-xl">👀</span> Hiển thị ${e.keyword.toLowerCase()}`,o.addEventListener("click",()=>{t.classList.contains("hidden")?(t.classList.remove("hidden"),o.innerHTML=`<span class="text-xl">🙈</span> Ẩn ${e.keyword.toLowerCase()}`):(t.classList.add("hidden"),o.innerHTML=`<span class="text-xl">👀</span> Hiển thị ${e.keyword.toLowerCase()}`)}),n.appendChild(o),n.appendChild(t)}})})});
